syntax.sqlite:
-- REAL: 8-byte IEEE floating point

CREATE TABLE measurements (
  temperature  REAL,
  latitude     REAL,
  longitude    REAL
);

syntax.postgresql:
CREATE TABLE users (
  country_code  CHAR(2) NOT NULL,        -- 고정: 'KR', 'US'
  username      VARCHAR(50) NOT NULL,     -- 가변: 최대 50자
  bio           VARCHAR(500),             -- 가변: 최대 500자
  email         VARCHAR(255) UNIQUE       -- 이메일은 255자 표준
);

CREATE TABLE posts (
  id       SERIAL PRIMARY KEY,
  title    VARCHAR(200) NOT NULL,
  content  TEXT NOT NULL,
  html     TEXT
);

syntax.mysql:
CREATE TABLE posts (
  id       INT AUTO_INCREMENT PRIMARY KEY,
  title    VARCHAR(200) NOT NULL,
  content  MEDIUMTEXT NOT NULL,  -- up to 16MB
  html     LONGTEXT              -- up to 4GB
);

syntax.mariadb:
CREATE TABLE posts (
  id       INT AUTO_INCREMENT PRIMARY KEY,
  title    VARCHAR(200) NOT NULL,
  content  MEDIUMTEXT NOT NULL,
  html     LONGTEXT
);

syntax.postgresql:
CREATE TABLE users (
  is_active   BOOLEAN NOT NULL DEFAULT TRUE,
  is_verified BOOLEAN DEFAULT FALSE
);

SELECT * FROM users WHERE is_active;  -- no '= TRUE' needed

syntax.mysql:
-- BOOLEAN = TINYINT(1)
CREATE TABLE users (
  is_active   BOOLEAN NOT NULL DEFAULT TRUE,
  is_verified BOOLEAN DEFAULT FALSE
);

SELECT * FROM users WHERE is_active = 1;

syntax.mariadb:
-- BOOLEAN = TINYINT(1)
CREATE TABLE users (
  is_active   BOOLEAN NOT NULL DEFAULT TRUE,
  is_verified BOOLEAN DEFAULT FALSE
);

SELECT * FROM users WHERE is_active = 1;

syntax.sqlite:
-- No native BOOLEAN. Use INTEGER 0/1.
CREATE TABLE users (
  is_active   INTEGER NOT NULL DEFAULT 1,
  is_verified INTEGER DEFAULT 0
);

syntax.postgresql:
CREATE TABLE events (
  event_date   DATE NOT NULL,
  start_time   TIME,
  created_at   TIMESTAMPTZ DEFAULT NOW(),  -- timezone-aware
  scheduled_at TIMESTAMP                    -- no timezone
);

-- INTERVAL for durations
SELECT created_at + INTERVAL '30 days' FROM events;

syntax.mariadb:
CREATE TABLE events (
  event_date   DATE NOT NULL,
  start_time   TIME,
  created_at   TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  scheduled_at DATETIME
);

syntax.postgresql:
CREATE TABLE products (
  metadata JSONB DEFAULT '{}'
);

-- Indexing for fast queries
CREATE INDEX idx_metadata ON products USING GIN (metadata);

-- Query JSON paths
SELECT * FROM products
WHERE metadata->>'color' = 'red'
  AND (metadata->>'weight')::numeric > 5;

syntax.mysql:
CREATE TABLE products (
  metadata JSON DEFAULT (JSON_OBJECT())
);

-- Functional index (MySQL 8.0+)
CREATE INDEX idx_color
  ON products ((CAST(metadata->>'$.color' AS CHAR(50))));

-- Query JSON paths
SELECT * FROM products
WHERE JSON_EXTRACT(metadata, '$.color') = 'red';

syntax.mariadb:
CREATE TABLE products (
  metadata JSON DEFAULT (JSON_OBJECT())
);

-- Query JSON paths
SELECT * FROM products
WHERE JSON_VALUE(metadata, '$.color') = 'red';

syntax.sqlite:
-- JSON stored as TEXT with json functions
CREATE TABLE products (
  metadata TEXT DEFAULT '{}'
);

-- Query JSON paths
SELECT * FROM products
WHERE json_extract(metadata, '$.color') = 'red';

syntax.postgresql:
CREATE TABLE users (
  id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
  name VARCHAR(100) NOT NULL
);

-- gen_random_uuid() is built-in since PG 13

syntax.mysql:
CREATE TABLE users (
  id CHAR(36) DEFAULT (UUID()) PRIMARY KEY,
  name VARCHAR(100) NOT NULL
);

-- Or for better performance:
-- id BINARY(16) DEFAULT (UUID_TO_BIN(UUID(), 1)) PRIMARY KEY

syntax.mariadb:
CREATE TABLE users (
  id CHAR(36) DEFAULT (UUID()) PRIMARY KEY,
  name VARCHAR(100) NOT NULL
);

-- UUID() built-in function

syntax.sqlite:
-- No native UUID. Generate in application layer.
CREATE TABLE users (
  id TEXT PRIMARY KEY,  -- store as text
  name TEXT NOT NULL
);

syntax.postgresql:
CREATE TABLE attachments (
  id      SERIAL PRIMARY KEY,
  name    VARCHAR(255) NOT NULL,
  data    BYTEA NOT NULL,
  mime    VARCHAR(100)
);

-- Insert binary data
INSERT INTO attachments (name, data, mime)
VALUES ('logo.png', '\x89504E47...', 'image/png');

syntax.mysql:
CREATE TABLE attachments (
  id      INT AUTO_INCREMENT PRIMARY KEY,
  name    VARCHAR(255) NOT NULL,
  data    MEDIUMBLOB NOT NULL,  -- up to 16MB
  mime    VARCHAR(100)
);

syntax.mariadb:
CREATE TABLE attachments (
  id      INT AUTO_INCREMENT PRIMARY KEY,
  name    VARCHAR(255) NOT NULL,
  data    MEDIUMBLOB NOT NULL,
  mime    VARCHAR(100)
);

syntax.sqlite:
CREATE TABLE attachments (
  id      INTEGER PRIMARY KEY AUTOINCREMENT,
  name    TEXT NOT NULL,
  data    BLOB NOT NULL,
  mime    TEXT
);

syntax.postgresql:
-- PostgreSQL uses CREATE TYPE for enums
CREATE TYPE user_status AS ENUM ('active', 'inactive', 'suspended');

CREATE TABLE users (
  status user_status NOT NULL DEFAULT 'active'
);

-- Adding values:
ALTER TYPE user_status ADD VALUE 'banned';

syntax.mysql:
CREATE TABLE users (
  status ENUM('active', 'inactive', 'suspended')
    NOT NULL DEFAULT 'active'
);

-- SET allows multiple values
CREATE TABLE products (
  tags SET('sale', 'new', 'featured', 'clearance')
);

syntax.mariadb:
CREATE TABLE users (
  status ENUM('active', 'inactive', 'suspended')
    NOT NULL DEFAULT 'active'
);

CREATE TABLE products (
  tags SET('sale', 'new', 'featured', 'clearance')
);

syntax.sqlite:
-- No native ENUM. Use CHECK constraint.
CREATE TABLE users (
  status TEXT NOT NULL DEFAULT 'active'
    CHECK (status IN ('active', 'inactive', 'suspended'))
);

syntax.postgresql:
CREATE TABLE articles (
  tags TEXT[] DEFAULT '{}',
  scores INTEGER[]
);

-- Insert
INSERT INTO articles (tags, scores)
VALUES ('{"sql", "database"}', '{95, 87, 92}');

-- Query: contains
SELECT * FROM articles WHERE 'sql' = ANY(tags);

-- GIN index for fast lookups
CREATE INDEX idx_tags ON articles USING GIN (tags);

syntax.mysql:
-- No native array type. Use JSON array.
CREATE TABLE articles (
  tags JSON DEFAULT (JSON_ARRAY())
);

INSERT INTO articles (tags)
VALUES (JSON_ARRAY('sql', 'database'));

-- Query
SELECT * FROM articles
WHERE JSON_CONTAINS(tags, '"sql"');

syntax.mariadb:
-- No native array type. Use JSON array.
CREATE TABLE articles (
  tags JSON DEFAULT (JSON_ARRAY())
);

SELECT * FROM articles
WHERE JSON_CONTAINS(tags, '"sql"');

syntax.sqlite:
-- No native array type. Use JSON array.
CREATE TABLE articles (
  tags TEXT DEFAULT '[]'
);

-- Query with json_each()
SELECT * FROM articles, json_each(articles.tags)
WHERE json_each.value = 'sql';
